// ─── HELPERS ──────────────────────────────────────────────────────────────────

export function getCasinosByMarket(marketCode: string): Casino[] {
  return casinos.filter((c) => c.markets.includes(marketCode));
}

export function getCasinoBySlug(slug: string): Casino | undefined {
  return casinos.find((c) => c.slug === slug);
}

export function getMarketByCode(code: string): Market | undefined {
  return markets.find((m) => m.code.toLowerCase() === code.toLowerCase());
}

export function getArticleBySlug(slug: string): Article | undefined {
  return articles.find((a) => a.slug === slug);
}
